{
    "level": "A1–A2",
    "intro": "W czasie przeszłym czasownik <strong>to be</strong> ma formy <strong>was / were</strong>. Używamy ich, gdy mówimy, <strong>jaki ktoś był</strong>, <strong>gdzie ktoś był</strong> albo <strong>co było prawdą wcześniej</strong>.",
    "rules": [
        {
            "label": "was",
            "color": "emerald",
            "text": "Z <strong>I / he / she / it</strong> używaj <strong>was</strong>.",
            "example": "I was tired. / She was at home."
        },
        {
            "label": "were",
            "color": "blue",
            "text": "Z <strong>you / we / they</strong> używaj <strong>were</strong>.",
            "example": "You were right. / They were late."
        },
        {
            "label": "Pytania bez did",
            "color": "amber",
            "text": "W pytaniach z <strong>to be</strong> nie potrzebujesz <strong>did</strong>.",
            "example": "Was he busy? / Were they ready?"
        }
    ]
}

{
    "title": "1. Formy was / were",
    "intro": "Zacznij od dwóch głównych form i zapamiętaj, z jakimi podmiotami występują.",
    "items": [
        {
            "label": "I / He / She / It",
            "title": "was",
            "subtitle": "I was happy. / It was cold."
        },
        {
            "label": "You / We / They",
            "title": "were",
            "subtitle": "You were late. / They were happy."
        },
        {
            "label": "Przeczenie",
            "title": "was not / were not",
            "subtitle": "wasn't / weren't to formy skrócone."
        },
        {
            "label": "Model",
            "title": "Subject + was / were",
            "subtitle": "She was at home. / We were ready."
        }
    ]
}

{
    "title": "2. Przeczenia",
    "intro": "Aby utworzyć przeczenie, dodaj <strong>not</strong> po <strong>was / were</strong>.",
    "rows": [
        {
            "en": "I was at home.",
            "ua": "I wasn't at home.",
            "note": "wasn't = was not"
        },
        {
            "en": "She was tired.",
            "ua": "She was not tired.",
            "note": "Pełna forma brzmi wyraźniej albo mocniej."
        },
        {
            "en": "They were late.",
            "ua": "They weren't late.",
            "note": "weren't = were not"
        }
    ],
    "warning": "📌 Z <strong>to be</strong> w przeszłości nie dodawaj <strong>didn't</strong>."
}

{
    "title": "3. Pytania",
    "sections": [
        {
            "label": "Was + I / he / she / it",
            "color": "emerald",
            "description": "Z <strong>I / he / she / it</strong> zaczynaj pytanie od <strong>was</strong>.",
            "examples": [
                {
                    "en": "Was he at work yesterday?",
                    "ua": "Czy on był wczoraj w pracy?"
                },
                {
                    "en": "Was it difficult?",
                    "ua": "Czy to było trudne?"
                }
            ]
        },
        {
            "label": "Were + you / we / they",
            "color": "blue",
            "description": "Z <strong>you / we / they</strong> postaw <strong>were</strong> przed podmiotem.",
            "examples": [
                {
                    "en": "Were you busy?",
                    "ua": "Czy byłeś zajęty?"
                },
                {
                    "en": "Were they ready?",
                    "ua": "Czy oni byli gotowi?"
                }
            ]
        },
        {
            "label": "Bez did",
            "color": "amber",
            "description": "Z <strong>to be</strong> po prostu robimy inwersję: <strong>was / were + subject</strong>.",
            "examples": [
                {
                    "en": "She was at home. → Was she at home?",
                    "ua": "Zmień zdanie twierdzące w pytanie bez did."
                },
                {
                    "en": "Where were you yesterday?",
                    "ua": "W pytaniach z where, when, why też zostaje was / were przed podmiotem."
                }
            ]
        }
    ]
}

{
    "title": "4. Krótkie odpowiedzi",
    "intro": "W krótkiej odpowiedzi powtórz <strong>was</strong> albo <strong>were</strong>.",
    "rows": [
        {
            "en": "Were you at home?",
            "ua": "Yes, I was. / No, I wasn't.",
            "note": "Po Were you...? odpowiadamy I was / I wasn't."
        },
        {
            "en": "Was she ready?",
            "ua": "Yes, she was. / No, she wasn't.",
            "note": "was → she was / she wasn't"
        },
        {
            "en": "Were they late?",
            "ua": "Yes, they were. / No, they weren't.",
            "note": "were → they were / they weren't"
        }
    ],
    "warning": "📌 W krótkiej odpowiedzi powtarzamy <strong>was / were</strong>, a nie <strong>did</strong>."
}

{
    "title": "5. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Mylenie was i were.",
            "wrong": "❌ They was late.",
            "right": "✅ <span class=\"font-mono\">They were late.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Dodawanie did do to be.",
            "wrong": "❌ Did she was at home?",
            "right": "✅ <span class=\"font-mono\">Was she at home?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zła krótka odpowiedź.",
            "wrong": "❌ Yes, they was.",
            "right": "✅ <span class=\"font-mono\">Yes, they were.</span>"
        }
    ]
}

